class Solution(object):
    def minimumRecolors(self, blocks, k):
        current = blocks[:k].count('W')
        result = current
        for i in range(k, len(blocks)):
            if blocks[i-k] == 'W':
                current -= 1
            if blocks[i] == 'W':
                current += 1
            result = min(result, current)
        return result
